using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents and raw SQL
            // (e.g. "SELECT * FROM c WHERE c.Discriminator = 'Blog'") keep working.
            b.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: "Id" now maps directly to Cosmos "id".
            // Old documents store id as "Blog|{key}" (discriminator-prefixed).
            // Restore the EF 8 layout: "Id" stays a regular JSON property and a
            // shadow "__id" property maps to the Cosmos "id" field.
            b.Property(e => e.Id).ToJsonProperty("Id");
            b.Property<string>("__id").ToJsonProperty("id");
            b.HasKey("__id");

            // Breaking change 3: HasIndex() now throws on the Cosmos provider
            // (it was silently ignored in EF 8). Removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

