using Microsoft.EntityFrameworkCore;

// Breaking change 4: Cosmos provider no longer allows synchronous I/O.
// ToList() / SaveChanges() throw InvalidOperationException; use async equivalents.
class SyncJob
{
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

